var COURSE_SQ_PL = [{day: 1, title: `Përshëndetje dhe fjalët e para`, title_native: `Pierwsze pozdrowienia`, focus: `Sot mëson përshëndetjet bazë që do t’i përdorësh sapo të mbërrish në Varshavë, Krakov ose Gdańsk. Qëllimi është të tingëllosh i sjellshëm në takime të shkurtra, në hotel, dyqan ose kafene.`, vocab: [{pl: `dzień dobry`, sq: `mirëmëngjes / mirëdita`, ipa: `xhen DO-bri`},{pl: `cześć`, sq: `përshëndetje / ç’kemi`, ipa: `çeshç`},{pl: `dobry wieczór`, sq: `mirëmbrëma`, ipa: `DO-bri VJE-çur`},{pl: `do widzenia`, sq: `mirupafshim`, ipa: `do vi-DZE-nja`},{pl: `proszę`, sq: `ju lutem / urdhëroni`, ipa: `PRO-she`},{pl: `dziękuję`, sq: `faleminderit`, ipa: `xhen-KU-ye`},{pl: `tak`, sq: `po`, ipa: `tak`},{pl: `nie`, sq: `jo`, ipa: `nje`},{pl: `przepraszam`, sq: `më falni`, ipa: `pshe-PRA-sham`},{pl: `pan`, sq: `zotëri`, ipa: `pan`}], phrases: [{pl: `Dzień dobry, proszę pana.`, sq: `Mirëdita, zotëri.`, ipa: `xhen DO-bri, PRO-she PA-na`},{pl: `Dzień dobry, proszę pani.`, sq: `Mirëdita, zonjë.`, ipa: `xhen DO-bri, PRO-she PA-nji`},{pl: `Cześć, jak się masz?`, sq: `Ç’kemi, si je?`, ipa: `çeshç, jak shen mash`},{pl: `Dziękuję bardzo.`, sq: `Faleminderit shumë.`, ipa: `xhen-KU-ye BAR-dzo`},{pl: `Do widzenia, miłego dnia.`, sq: `Mirupafshim, ditë të mbarë.`, ipa: `do vi-DZE-nja, mi-WE-go dnja`},{pl: `Przepraszam, nie rozumiem.`, sq: `Më falni, nuk kuptoj.`, ipa: `pshe-PRA-sham, nje ro-ZU-mjem`}], grammar: `Në polonisht ka forma më formale dhe më joformale të komunikimit. Dzień dobry është zgjedhje e sigurt në pothuajse çdo situatë, ndërsa cześć përdoret me miq, të rinj ose njerëz që tashmë i njeh. Pan do të thotë “zotëri” dhe pani do të thotë “zonjë”; përdoren shpesh për respekt në shërbime.`, practice: [`Thuaj me zë të lartë tre herë: Dzień dobry dhe Do widzenia.`,`Imagjino se hyn në një hotel në Kraków dhe përshëndet recepsionistin.`,`Përkthe në polonisht: “Faleminderit shumë.”`,`Zgjidh formën më të sigurt për një të panjohur: cześć apo dzień dobry?`,`Shkruaj një mini-dialog me dy rreshta: përshëndetje dhe mirupafshim.`]},{day: 2, title: `Prezantimi i vetes`, title_native: `Przedstawianie się`, focus: `Sot mëson të thuash emrin, vendin nga vjen dhe disa fraza të thjeshta për t’u prezantuar. Kjo është e dobishme kur takon dikë në hostel, në tur në Wrocław ose në një kafene në Poznań.`, vocab: [{pl: `imię`, sq: `emër`, ipa: `I-mje`},{pl: `nazywam się`, sq: `quhem`, ipa: `na-ZI-vam shen`},{pl: `jestem`, sq: `jam`, ipa: `JES-tem`},{pl: `Albania`, sq: `Shqipëria`, ipa: `al-BA-nja`},{pl: `Polska`, sq: `Polonia`, ipa: `POL-ska`},{pl: `turysta`, sq: `turist`, ipa: `tu-RIS-ta`},{pl: `turystka`, sq: `turiste`, ipa: `tu-RIS-tka`},{pl: `miło`, sq: `kënaqësi`, ipa: `MI-wo`},{pl: `skąd`, sq: `nga ku`, ipa: `skond`},{pl: `też`, sq: `gjithashtu`, ipa: `tesh`}], phrases: [{pl: `Nazywam się Arben.`, sq: `Quhem Arben.`, ipa: `na-ZI-vam shen AR-ben`},{pl: `Jestem z Albanii.`, sq: `Jam nga Shqipëria.`, ipa: `JES-tem z al-BA-nji`},{pl: `A ty?`, sq: `Po ti?`, ipa: `a ti`},{pl: `Miło mi.`, sq: `Kënaqësi.`, ipa: `MI-wo mi`},{pl: `Ja też jestem turystą.`, sq: `Edhe unë jam turist.`, ipa: `ja tesh JES-tem tu-RIS-ton`},{pl: `Skąd jesteś?`, sq: `Nga je?`, ipa: `skond JES-tesh`}], grammar: `Në polonisht, “jam nga Shqipëria” thuhet Jestem z Albanii. Fjala z do të thotë “nga” në këtë kontekst. Për meshkuj thuhet turysta, ndërsa për femra turystka; polonishtja shpesh ndryshon formën sipas gjinisë.`, practice: [`Prezanto veten në polonisht me emrin tënd.`,`Thuaj: “Jam nga Shqipëria.”`,`Pyet dikë: “Nga je?”`,`Përsërit Miło mi pesë herë me ritëm natyral.`,`Krijo një dialog të shkurtër mes dy turistëve në Varshavë.`]},{day: 3, title: `Fraza thelbësore për udhëtim`, title_native: `Podstawowe zwroty w podróży`, focus: `Sot mëson frazat që të ndihmojnë kur nuk kupton, kur kërkon ndihmë ose kur do të flasësh më ngadalë. Këto fraza janë shumë të rëndësishme në stacion treni, aeroport ose qendër qyteti.`, vocab: [{pl: `pomoc`, sq: `ndihmë`, ipa: `PO-mots`},{pl: `rozumiem`, sq: `kuptoj`, ipa: `ro-ZU-mjem`},{pl: `mówić`, sq: `flas`, ipa: `MU-viç`},{pl: `wolno`, sq: `ngadalë`, ipa: `VOL-no`},{pl: `szybko`, sq: `shpejt`, ipa: `SHIP-ko`},{pl: `jeszcze raz`, sq: `edhe një herë`, ipa: `JESH-çe ras`},{pl: `po polsku`, sq: `polonisht`, ipa: `po POL-sku`},{pl: `po angielsku`, sq: `anglisht`, ipa: `po an-GJEL-sku`},{pl: `mało`, sq: `pak`, ipa: `MA-wo`},{pl: `dobrze`, sq: `mirë`, ipa: `DOB-zhe`}], phrases: [{pl: `Czy mówi pan po angielsku?`, sq: `A flisni anglisht, zotëri?`, ipa: `çi MU-vi pan po an-GJEL-sku`},{pl: `Czy mówi pani po angielsku?`, sq: `A flisni anglisht, zonjë?`, ipa: `çi MU-vi PA-nji po an-GJEL-sku`},{pl: `Mówię mało po polsku.`, sq: `Flas pak polonisht.`, ipa: `MU-vjen MA-wo po POL-sku`},{pl: `Proszę mówić wolniej.`, sq: `Ju lutem flisni më ngadalë.`, ipa: `PRO-she MU-viç VOL-njej`},{pl: `Jeszcze raz, proszę.`, sq: `Edhe një herë, ju lutem.`, ipa: `JESH-çe ras, PRO-she`},{pl: `Potrzebuję pomocy.`, sq: `Kam nevojë për ndihmë.`, ipa: `po-tshe-BU-ye PO-mo-tsi`}], grammar: `Pyetjet në polonisht shpesh fillojnë me czy, por në të folur mund të kuptohen edhe nga intonacioni. Czy mówi pan...? është formale për një burrë, ndërsa Czy mówi pani...? është formale për një grua. Për udhëtarët, këto forma janë shumë të sigurta dhe të sjellshme.`, practice: [`Thuaj në polonisht: “Flas pak polonisht.”`,`Pyet një zonjë nëse flet anglisht.`,`Kërko që dikush të flasë më ngadalë.`,`Përkthe: Potrzebuję pomocy.`,`Bëj një dialog ku nuk kupton një udhëzim në stacion.`]},{day: 4, title: `Numrat 0–20 dhe çmimet e vogla`, title_native: `Liczby od zera do dwudziestu`, focus: `Sot mëson numrat bazë për të kuptuar çmime, dhoma hoteli, platforma treni dhe porosi në kafene. Numrat janë të domosdoshëm në çdo qytet polak.`, vocab: [{pl: `zero`, sq: `zero`, ipa: `ZE-ro`},{pl: `jeden`, sq: `një`, ipa: `JE-den`},{pl: `dwa`, sq: `dy`, ipa: `dva`},{pl: `trzy`, sq: `tre`, ipa: `tshih`},{pl: `cztery`, sq: `katër`, ipa: `çTE-ri`},{pl: `pięć`, sq: `pesë`, ipa: `pjenç`},{pl: `sześć`, sq: `gjashtë`, ipa: `sheshç`},{pl: `siedem`, sq: `shtatë`, ipa: `SHE-dem`},{pl: `osiem`, sq: `tetë`, ipa: `O-shem`},{pl: `dziesięć`, sq: `dhjetë`, ipa: `XHE-shenç`}], phrases: [{pl: `Jeden bilet, proszę.`, sq: `Një biletë, ju lutem.`, ipa: `JE-den BI-let, PRO-she`},{pl: `Dwa bilety, proszę.`, sq: `Dy bileta, ju lutem.`, ipa: `dva BI-le-ti, PRO-she`},{pl: `Ile to kosztuje?`, sq: `Sa kushton kjo?`, ipa: `I-le to kosh-TU-ye`},{pl: `To kosztuje dziesięć złotych.`, sq: `Kjo kushton dhjetë zloty.`, ipa: `to kosh-TU-ye XHE-shenç ZWO-tih`},{pl: `Mam pięć minut.`, sq: `Kam pesë minuta.`, ipa: `mam pjenç MI-nut`},{pl: `Pokój numer trzy.`, sq: `Dhoma numër tre.`, ipa: `PO-kuy NU-mer tshih`}], grammar: `Në polonisht, monedha quhet złoty. Pas disa numrave forma mund të ndryshojë: jeden złoty, dwa złote, pięć złotych. Për udhëtim, më e rëndësishmja është të njohësh tingullin e numrave kur dëgjon çmime ose orare.`, practice: [`Numëro nga zero në dhjetë në polonisht.`,`Kërko dy bileta.`,`Pyet: “Sa kushton kjo?”`,`Thuaj numrin e një dhome hoteli: Pokój numer trzy.`,`Shkruaj pesë çmime imagjinare me numra nga 1 deri 10.`]},{day: 5, title: `Numrat 20–100 dhe koha`, title_native: `Liczby do stu i czas`, focus: `Sot zgjeron numrat për të kuptuar orare, çmime më të larta dhe distanca në qytete si Łódź ose Katowice. Do të praktikosh edhe fjalë të dobishme për kohën.`, vocab: [{pl: `jedenaście`, sq: `njëmbëdhjetë`, ipa: `je-de-NASH-çe`},{pl: `dwanaście`, sq: `dymbëdhjetë`, ipa: `dva-NASH-çe`},{pl: `dwadzieścia`, sq: `njëzet`, ipa: `dva-DZJESH-ça`},{pl: `trzydzieści`, sq: `tridhjetë`, ipa: `tshih-DZJESH-çi`},{pl: `czterdzieści`, sq: `dyzet`, ipa: `çter-DZJESH-çi`},{pl: `pięćdziesiąt`, sq: `pesëdhjetë`, ipa: `pjenj-XHE-shont`},{pl: `sto`, sq: `njëqind`, ipa: `sto`},{pl: `godzina`, sq: `orë`, ipa: `go-DZHI-na`},{pl: `minuta`, sq: `minutë`, ipa: `mi-NU-ta`},{pl: `teraz`, sq: `tani`, ipa: `TE-ras`}], phrases: [{pl: `Która godzina?`, sq: `Sa është ora?`, ipa: `KTU-ra go-DZHI-na`},{pl: `Jest ósma.`, sq: `Është ora tetë.`, ipa: `jest US-ma`},{pl: `Za pięć minut.`, sq: `Pas pesë minutash.`, ipa: `za pjenç MI-nut`},{pl: `Mam dwadzieścia złotych.`, sq: `Kam njëzet zloty.`, ipa: `mam dva-DZJESH-ça ZWO-tih`},{pl: `To jest za drogie.`, sq: `Kjo është shumë e shtrenjtë.`, ipa: `to jest za DRO-gje`},{pl: `Pociąg jest o dziesiątej.`, sq: `Treni është në orën dhjetë.`, ipa: `PO-çong jest o xhe-SHON-tej`}], grammar: `Për të pyetur orën përdor Która godzina? Në përgjigje, polonishtja përdor forma si Jest ósma për “është ora tetë”. Për transport, mund të thuash o dziesiątej për “në orën dhjetë”.`, practice: [`Thuaj numrat 20, 30, 40, 50 dhe 100.`,`Pyet dikë sa është ora.`,`Thuaj: “Treni është në orën dhjetë.”`,`Imagjino një çmim 50 zloty dhe thuaje në polonisht.`,`Krijo tre fjali me minuta: 5, 10 dhe 20 minuta.`]},{day: 6, title: `Në aeroport`, title_native: `Na lotnisku`, focus: `Sot mëson fjalë dhe fraza për aeroportin, kontrollin e pasaportës dhe bagazhin. Kjo është e dobishme në Aeroportin Chopin në Varshavë ose në aeroportin e Kraków-Balice.`, vocab: [{pl: `lotnisko`, sq: `aeroport`, ipa: `lot-NIS-ko`},{pl: `paszport`, sq: `pasaportë`, ipa: `PASH-port`},{pl: `bagaż`, sq: `bagazh`, ipa: `BA-gazh`},{pl: `walizka`, sq: `valixhe`, ipa: `va-LIS-ka`},{pl: `bramka`, sq: `porta e imbarkimit`, ipa: `BRAM-ka`},{pl: `kontrola`, sq: `kontroll`, ipa: `kon-TRO-la`},{pl: `bilet`, sq: `biletë`, ipa: `BI-let`},{pl: `samolot`, sq: `avion`, ipa: `sa-MO-lot`},{pl: `przylot`, sq: `mbërritje`, ipa: `PSHI-lot`},{pl: `odlot`, sq: `nisje`, ipa: `OD-lot`}], phrases: [{pl: `Gdzie jest kontrola paszportowa?`, sq: `Ku është kontrolli i pasaportave?`, ipa: `gje jest kon-TRO-la pash-por-TO-va`},{pl: `To jest mój paszport.`, sq: `Kjo është pasaporta ime.`, ipa: `to jest muy PASH-port`},{pl: `Mam jedną walizkę.`, sq: `Kam një valixhe.`, ipa: `mam JED-non va-LIS-ken`},{pl: `Gdzie jest bramka numer pięć?`, sq: `Ku është porta numër pesë?`, ipa: `gje jest BRAM-ka NU-mer pjenç`},{pl: `Mój bagaż zaginął.`, sq: `Bagazhi im ka humbur.`, ipa: `muy BA-gazh za-GI-now`},{pl: `Kiedy jest odlot?`, sq: `Kur është nisja?`, ipa: `KJE-di jest OD-lot`}], grammar: `Fjala gdzie do të thotë “ku” dhe është shumë e dobishme për udhëtarët. Mund ta vendosësh para shumë emrave: Gdzie jest lotnisko?, Gdzie jest bramka?, Gdzie jest bagaż? Struktura Gdzie jest...? është një nga format më praktike për ditët e para.`, practice: [`Pyet ku është kontrolli i pasaportave.`,`Thuaj se ke një valixhe.`,`Pyet për portën numër pesë.`,`Përkthe: Mój bagaż zaginął.`,`Bëj një dialog të shkurtër me një punonjës aeroporti.`]},{day: 7, title: `Drejtimet dhe vendndodhjet`, title_native: `Kierunki i miejsca`, focus: `Sot mëson të pyesësh për rrugë dhe të kuptosh drejtime bazë në qendër të një qyteti polak. Kjo ndihmon kur kërkon Rynek Główny në Kraków ose Stare Miasto në Varshavë.`, vocab: [{pl: `gdzie`, sq: `ku`, ipa: `gje`},{pl: `tutaj`, sq: `këtu`, ipa: `TU-taj`},{pl: `tam`, sq: `atje`, ipa: `tam`},{pl: `prosto`, sq: `drejt`, ipa: `PRO-sto`},{pl: `w lewo`, sq: `majtas`, ipa: `v LE-vo`},{pl: `w prawo`, sq: `djathtas`, ipa: `v PRA-vo`},{pl: `ulica`, sq: `rrugë`, ipa: `u-LI-tsa`},{pl: `plac`, sq: `shesh`, ipa: `plats`},{pl: `centrum`, sq: `qendër`, ipa: `TSEN-trum`},{pl: `blisko`, sq: `afër`, ipa: `BLIS-ko`}], phrases: [{pl: `Gdzie jest centrum?`, sq: `Ku është qendra?`, ipa: `gje jest TSEN-trum`},{pl: `Proszę iść prosto.`, sq: `Ju lutem shkoni drejt.`, ipa: `PRO-she iç PRO-sto`},{pl: `Potem w lewo.`, sq: `Pastaj majtas.`, ipa: `PO-tem v LE-vo`},{pl: `To jest blisko.`, sq: `Është afër.`, ipa: `to jest BLIS-ko`},{pl: `To jest daleko.`, sq: `Është larg.`, ipa: `to jest da-LE-ko`},{pl: `Czy to jest ta ulica?`, sq: `A është kjo ajo rruga?`, ipa: `çi to jest ta u-LI-tsa`}], grammar: `Për drejtimet përdor shpesh formën Proszę iść, që do të thotë “ju lutem shkoni”. W lewo është “majtas” dhe w prawo është “djathtas”. Në qytetet polake, njerëzit shpesh përdorin plac për shesh dhe ulica për rrugë.`, practice: [`Pyet ku është qendra.`,`Jep udhëzim: drejt, pastaj majtas.`,`Thuaj në polonisht: “Është afër.”`,`Pyet nëse kjo është rruga e duhur.`,`Imagjino se je në Stare Miasto dhe kërkon sheshin kryesor.`]},{day: 8, title: `Transporti publik`, title_native: `Transport publiczny`, focus: `Sot mëson të blesh bileta dhe të përdorësh tramvaj, autobus dhe metro. Kjo është veçanërisht e dobishme në Varshavë, ku metroja dhe tramvajet janë shumë praktike.`, vocab: [{pl: `autobus`, sq: `autobus`, ipa: `au-TO-bus`},{pl: `tramwaj`, sq: `tramvaj`, ipa: `TRAM-vaj`},{pl: `metro`, sq: `metro`, ipa: `ME-tro`},{pl: `bilet`, sq: `biletë`, ipa: `BI-let`},{pl: `przystanek`, sq: `stacion autobusi/tramvaji`, ipa: `pshi-STA-nek`},{pl: `stacja`, sq: `stacion`, ipa: `STA-tsja`},{pl: `kierunek`, sq: `drejtim`, ipa: `kje-RU-nek`},{pl: `linia`, sq: `linjë`, ipa: `LI-nja`},{pl: `ważny`, sq: `i vlefshëm`, ipa: `VAZH-ni`},{pl: `kontroler`, sq: `kontrollor`, ipa: `kon-TRO-ler`}], phrases: [{pl: `Poproszę bilet normalny.`, sq: `Dua një biletë normale, ju lutem.`, ipa: `po-PRO-she BI-let nor-MAL-ni`},{pl: `Gdzie jest przystanek?`, sq: `Ku është stacioni?`, ipa: `gje jest pshi-STA-nek`},{pl: `Czy ten bilet jest ważny?`, sq: `A është kjo biletë e vlefshme?`, ipa: `çi ten BI-let jest VAZH-ni`},{pl: `Która linia jedzie do centrum?`, sq: `Cila linjë shkon në qendër?`, ipa: `KTU-ra LI-nja JE-xhe do TSEN-trum`},{pl: `Jadę do stacji Centrum.`, sq: `Po shkoj në stacionin Centrum.`, ipa: `JA-den do STA-tsji TSEN-trum`},{pl: `Muszę wysiąść tutaj.`, sq: `Duhet të zbres këtu.`, ipa: `MU-shen VI-shonç TU-taj`}], grammar: `Folja jechać do të thotë “të shkosh me mjet transporti”. Forma Jadę do... do të thotë “po shkoj në...”. Në transport, përdor do për destinacionin: do centrum, do hotelu, do stacji.`, practice: [`Kërko një biletë normale.`,`Pyet ku është stacioni i autobusit.`,`Thuaj destinacionin tënd me Jadę do...`,`Pyet nëse bileta është e vlefshme.`,`Shkruaj një mini-dialog në një stacion tramvaji.`]},{day: 9, title: `Në taksi ose rideshare`, title_native: `W taksówce`, focus: `Sot mëson të flasësh me shoferin dhe të shpjegosh destinacionin. Kjo është e dobishme pas mbërritjes vonë në aeroport ose kur udhëton me bagazh.`, vocab: [{pl: `taksówka`, sq: `taksi`, ipa: `tak-SUF-ka`},{pl: `kierowca`, sq: `shofer`, ipa: `kje-ROV-tsa`},{pl: `adres`, sq: `adresë`, ipa: `A-dres`},{pl: `hotel`, sq: `hotel`, ipa: `HO-tel`},{pl: `dworzec`, sq: `stacion treni`, ipa: `DVO-zhets`},{pl: `lotnisko`, sq: `aeroport`, ipa: `lot-NIS-ko`},{pl: `szybciej`, sq: `më shpejt`, ipa: `SHIP-çej`},{pl: `wolniej`, sq: `më ngadalë`, ipa: `VOL-njej`},{pl: `rachunek`, sq: `faturë`, ipa: `ra-HU-nek`},{pl: `gotówka`, sq: `para në dorë`, ipa: `go-TUF-ka`}], phrases: [{pl: `Proszę jechać na ten adres.`, sq: `Ju lutem shkoni në këtë adresë.`, ipa: `PRO-she JE-haç na ten A-dres`},{pl: `Ile to będzie kosztować?`, sq: `Sa do të kushtojë?`, ipa: `I-le to BEN-xhe kosh-TO-vaç`},{pl: `Czy mogę zapłacić kartą?`, sq: `A mund të paguaj me kartë?`, ipa: `çi MO-gen za-PWA-çiç KAR-ton`},{pl: `Proszę zatrzymać się tutaj.`, sq: `Ju lutem ndaloni këtu.`, ipa: `PRO-she za-tshi-MAç shen TU-taj`},{pl: `Jadę na dworzec.`, sq: `Po shkoj në stacionin e trenit.`, ipa: `JA-den na DVO-zhets`},{pl: `Poproszę rachunek.`, sq: `Dua faturën, ju lutem.`, ipa: `po-PRO-she ra-HU-nek`}], grammar: `Për destinacione përdoret shpesh na ose do, sipas vendit. Mund të thuash Jadę na dworzec për “po shkoj në stacion” dhe Jadę do hotelu për “po shkoj në hotel”. Në praktikë, shoferi do të kuptojë edhe nëse përdor strukturë të thjeshtë me adresën.`, practice: [`Thuaj shoferit të shkojë në këtë adresë.`,`Pyet nëse mund të paguash me kartë.`,`Kërko që shoferi të ndalojë këtu.`,`Thuaj: “Po shkoj në aeroport.”`,`Bëj dialog me 6 rreshta mes teje dhe shoferit.`]},{day: 10, title: `Check-in në hotel`, title_native: `Meldunek w hotelu`, focus: `Sot mëson fraza për recepsionin, rezervimin dhe dhomën. Kjo të ndihmon kur mbërrin në hotel në Gdańsk, Zakopane ose Lublin.`, vocab: [{pl: `hotel`, sq: `hotel`, ipa: `HO-tel`},{pl: `rezerwacja`, sq: `rezervim`, ipa: `re-zer-VA-tsja`},{pl: `pokój`, sq: `dhomë`, ipa: `PO-kuy`},{pl: `klucz`, sq: `çelës`, ipa: `kluç`},{pl: `recepcja`, sq: `recepsion`, ipa: `re-TSEP-tsja`},{pl: `paszport`, sq: `pasaportë`, ipa: `PASH-port`},{pl: `noc`, sq: `natë`, ipa: `nots`},{pl: `śniadanie`, sq: `mëngjes`, ipa: `shnja-DA-nje`},{pl: `winda`, sq: `ashensor`, ipa: `VIN-da`},{pl: `łazienka`, sq: `banjë`, ipa: `wa-ZJEN-ka`}], phrases: [{pl: `Mam rezerwację.`, sq: `Kam rezervim.`, ipa: `mam re-zer-VA-tsjen`},{pl: `Na nazwisko Cannon.`, sq: `Në mbiemrin Cannon.`, ipa: `na naz-VIS-ko Cannon`},{pl: `Czy śniadanie jest w cenie?`, sq: `A është mëngjesi i përfshirë në çmim?`, ipa: `çi shnja-DA-nje jest v TSE-nje`},{pl: `Gdzie jest winda?`, sq: `Ku është ashensori?`, ipa: `gje jest VIN-da`},{pl: `Poproszę klucz do pokoju.`, sq: `Dua çelësin e dhomës, ju lutem.`, ipa: `po-PRO-she kluç do po-KO-yu`},{pl: `O której jest wymeldowanie?`, sq: `Në ç’orë është check-out?`, ipa: `o KTU-rej jest vi-mel-do-VA-nje`}], grammar: `Për rezervim përdor Mam rezerwację, një frazë shumë e zakonshme. Në hotel mund të dëgjosh pokój jednoosobowy për dhomë teke dhe pokój dwuosobowy për dhomë dyshe. Forma do pokoju do të thotë “për në dhomë” ose “e dhomës” në kontekstin e çelësit.`, practice: [`Thuaj se ke rezervim.`,`Pyet nëse mëngjesi është i përfshirë.`,`Pyet ku është ashensori.`,`Kërko çelësin e dhomës.`,`Bëj një dialog check-in me 8 rreshta.`]},{day: 11, title: `Problemet në hotel`, title_native: `Problemy w hotelu`, focus: `Sot mëson të raportosh probleme të zakonshme në dhomë, si interneti, ngrohja ose zhurma. Këto fraza të ndihmojnë të jesh i qartë dhe i sjellshëm.`, vocab: [{pl: `problem`, sq: `problem`, ipa: `PRO-blem`},{pl: `internet`, sq: `internet`, ipa: `IN-ter-net`},{pl: `klimatyzacja`, sq: `kondicioner`, ipa: `kli-ma-ti-ZA-tsja`},{pl: `ogrzewanie`, sq: `ngrohje`, ipa: `o-gzhe-VA-nje`},{pl: `hałas`, sq: `zhurmë`, ipa: `HA-was`},{pl: `ręcznik`, sq: `peshqir`, ipa: `RENÇ-nik`},{pl: `pościel`, sq: `çarçafë`, ipa: `POSH-çel`},{pl: `brudny`, sq: `i pistë`, ipa: `BRUD-ni`},{pl: `zimno`, sq: `ftohtë`, ipa: `ZHIM-no`},{pl: `gorąco`, sq: `nxehtë`, ipa: `go-RON-tso`}], phrases: [{pl: `Internet nie działa.`, sq: `Interneti nuk punon.`, ipa: `IN-ter-net nje DZJA-wa`},{pl: `W pokoju jest zimno.`, sq: `Në dhomë është ftohtë.`, ipa: `v po-KO-yu jest ZHIM-no`},{pl: `Potrzebuję ręcznika.`, sq: `Kam nevojë për një peshqir.`, ipa: `po-tshe-BU-ye RENÇ-ni-ka`},{pl: `Jest za głośno.`, sq: `Ka shumë zhurmë.`, ipa: `jest za GWOSH-no`},{pl: `Czy można zmienić pokój?`, sq: `A mund të ndërroj dhomën?`, ipa: `çi MOZH-na ZMJE-niç PO-kuy`},{pl: `Klimatyzacja nie działa.`, sq: `Kondicioneri nuk punon.`, ipa: `kli-ma-ti-ZA-tsja nje DZJA-wa`}], grammar: `Nie działa do të thotë “nuk punon” dhe përdoret për pajisje, internet, kondicioner ose makinë bilete. Jest zimno do të thotë “është ftohtë”, ndërsa jest gorąco do të thotë “është nxehtë”. Za do të thotë “tepër” kur përdoret para mbiemrave: za głośno, za drogo.`, practice: [`Raporto se interneti nuk punon.`,`Thuaj se në dhomë është ftohtë.`,`Kërko një peshqir.`,`Pyet nëse mund të ndërrosh dhomën.`,`Krijo një dialog me recepsionin për zhurmën.`]},{day: 12, title: `Në kafene`, title_native: `W kawiarni`, focus: `Sot mëson të porosisësh kafe, çaj dhe ëmbëlsira në një kafene polake. Kjo është perfekte për një mëngjes në Kraków ose një pushim në Varshavë.`, vocab: [{pl: `kawa`, sq: `kafe`, ipa: `KA-va`},{pl: `herbata`, sq: `çaj`, ipa: `her-BA-ta`},{pl: `woda`, sq: `ujë`, ipa: `VO-da`},{pl: `mleko`, sq: `qumësht`, ipa: `MLE-ko`},{pl: `cukier`, sq: `sheqer`, ipa: `TSU-kjer`},{pl: `ciasto`, sq: `kek / ëmbëlsirë`, ipa: `ÇAS-to`},{pl: `sernik`, sq: `cheesecake polak`, ipa: `SER-nik`},{pl: `stolik`, sq: `tavolinë`, ipa: `STO-lik`},{pl: `menu`, sq: `menu`, ipa: `ME-nu`},{pl: `filiżanka`, sq: `filxhan`, ipa: `fi-li-ZHAN-ka`}], phrases: [{pl: `Poproszę kawę.`, sq: `Dua një kafe, ju lutem.`, ipa: `po-PRO-she KA-ven`},{pl: `Poproszę herbatę.`, sq: `Dua një çaj, ju lutem.`, ipa: `po-PRO-she her-BA-ten`},{pl: `Z mlekiem czy bez mleka?`, sq: `Me qumësht apo pa qumësht?`, ipa: `z MLE-kjem çi bez MLE-ka`},{pl: `Bez cukru, proszę.`, sq: `Pa sheqer, ju lutem.`, ipa: `bez TSU-kru, PRO-she`},{pl: `Czy jest wolny stolik?`, sq: `A ka tavolinë të lirë?`, ipa: `çi jest VOL-ni STO-lik`},{pl: `Poproszę sernik.`, sq: `Dua sernik, ju lutem.`, ipa: `po-PRO-she SER-nik`}], grammar: `Poproszę është mënyrë shumë e sjellshme për të porositur dhe do të thotë afërsisht “do të doja”. Me dhe pa shprehen me z dhe bez: z mlekiem, bez cukru. Në kafene, mjafton të thuash Poproszę + emri i gjësë që dëshiron.`, practice: [`Porosit një kafe pa sheqer.`,`Pyet nëse ka tavolinë të lirë.`,`Porosit sernik.`,`Përkthe: Z mlekiem czy bez mleka?`,`Krijo një dialog të shkurtër në një kafene në Poznań.`]},{day: 13, title: `Ushqimi polak`, title_native: `Polskie jedzenie`, focus: `Sot mëson emrat e ushqimeve tipike polake dhe si të pyesësh për përbërësit. Kjo të ndihmon të porosisësh pierogi, zupa ose bigos pa pasiguri.`, vocab: [{pl: `jedzenie`, sq: `ushqim`, ipa: `je-DZE-nje`},{pl: `pierogi`, sq: `pirogë polake`, ipa: `pje-RO-gi`},{pl: `zupa`, sq: `supë`, ipa: `ZU-pa`},{pl: `barszcz`, sq: `supë panxhari`, ipa: `barshtsh`},{pl: `bigos`, sq: `gjellë me lakër dhe mish`, ipa: `BI-gos`},{pl: `chleb`, sq: `bukë`, ipa: `hlep`},{pl: `mięso`, sq: `mish`, ipa: `MJEN-so`},{pl: `ryba`, sq: `peshk`, ipa: `RI-ba`},{pl: `warzywa`, sq: `perime`, ipa: `va-ZHI-va`},{pl: `ser`, sq: `djathë`, ipa: `ser`}], phrases: [{pl: `Co pan poleca?`, sq: `Çfarë rekomandoni, zotëri?`, ipa: `tso pan po-LE-tsa`},{pl: `Co pani poleca?`, sq: `Çfarë rekomandoni, zonjë?`, ipa: `tso PA-nji po-LE-tsa`},{pl: `Czy to jest z mięsem?`, sq: `A është kjo me mish?`, ipa: `çi to jest z MJEN-sem`},{pl: `Poproszę pierogi.`, sq: `Dua pierogi, ju lutem.`, ipa: `po-PRO-she pje-RO-gi`},{pl: `Czy macie zupę?`, sq: `A keni supë?`, ipa: `çi MA-çje ZU-pen`},{pl: `To jest bardzo dobre.`, sq: `Kjo është shumë e mirë.`, ipa: `to jest BAR-dzo DOB-re`}], grammar: `Czy to jest z...? do të thotë “A është kjo me...?” dhe është shumë e dobishme për përbërës. Për shembull: Czy to jest z mięsem? ose Czy to jest z serem? Në restorante polake, polecać do të thotë “të rekomandosh”.`, practice: [`Pyet nëse një ushqim është me mish.`,`Kërko rekomandim nga kamerieri.`,`Porosit pierogi.`,`Thuaj se ushqimi është shumë i mirë.`,`Shkruaj tre pyetje për përbërës: mish, djathë, perime.`]},{day: 14, title: `Në restorant`, title_native: `W restauracji`, focus: `Sot mëson të rezervosh tavolinë, të kërkosh menu dhe të paguash në restorant. Kjo është e dobishme për darkë në një restorant tradicional në Kraków ose Gdańsk.`, vocab: [{pl: `restauracja`, sq: `restorant`, ipa: `res-tau-RA-tsja`},{pl: `kelner`, sq: `kamerier`, ipa: `KEL-ner`},{pl: `kelnerka`, sq: `kameriere`, ipa: `kel-NER-ka`},{pl: `rachunek`, sq: `llogari / faturë`, ipa: `ra-HU-nek`},{pl: `menu`, sq: `menu`, ipa: `ME-nu`},{pl: `danie`, sq: `pjatë`, ipa: `DA-nje`},{pl: `deser`, sq: `ëmbëlsirë`, ipa: `DE-ser`},{pl: `napój`, sq: `pije`, ipa: `NA-puy`},{pl: `rezerwacja`, sq: `rezervim`, ipa: `re-zer-VA-tsja`},{pl: `stolik`, sq: `tavolinë`, ipa: `STO-lik`}], phrases: [{pl: `Stolik dla dwóch osób, proszę.`, sq: `Tavolinë për dy persona, ju lutem.`, ipa: `STO-lik dla dvuh O-sub, PRO-she`},{pl: `Czy mogę zobaczyć menu?`, sq: `A mund ta shoh menunë?`, ipa: `çi MO-gen zo-BA-çiç ME-nu`},{pl: `Co jest specjalnością domu?`, sq: `Cila është specialiteti i shtëpisë?`, ipa: `tso jest spe-tsjal-NOSH-çjon DO-mu`},{pl: `Poproszę rachunek.`, sq: `Llogarinë, ju lutem.`, ipa: `po-PRO-she ra-HU-nek`},{pl: `Było bardzo dobre.`, sq: `Ishte shumë e mirë.`, ipa: `BI-wo BAR-dzo DOB-re`},{pl: `Czy napiwek jest wliczony?`, sq: `A është bakshishi i përfshirë?`, ipa: `çi NA-pi-vek jest vli-ÇO-ni`}], grammar: `Dla do të thotë “për” kur flet për persona: dla dwóch osób, dla jednej osoby. Në polonisht, forma osób përdoret pas numrave si dwóch, trzech ose czterech. Në restorant, Poproszę rachunek është fraza kryesore për të kërkuar llogarinë.`, practice: [`Kërko tavolinë për dy persona.`,`Pyet për menunë.`,`Pyet për specialitetin e shtëpisë.`,`Kërko llogarinë.`,`Krijo një dialog darke me 8 rreshta.`]},{day: 15, title: `Dieta dhe alergjitë`, title_native: `Dieta i alergie`, focus: `Sot mëson të shpjegosh kufizime ushqimore, alergji dhe preferenca. Kjo është e rëndësishme në restorante, kafene dhe tregje ushqimore.`, vocab: [{pl: `alergia`, sq: `alergji`, ipa: `a-LER-gja`},{pl: `orzechy`, sq: `arra`, ipa: `o-ZHE-hi`},{pl: `mleko`, sq: `qumësht`, ipa: `MLE-ko`},{pl: `gluten`, sq: `gluten`, ipa: `GLU-ten`},{pl: `wegetariański`, sq: `vegjetarian`, ipa: `ve-ge-ta-RJAN-ski`},{pl: `wegański`, sq: `vegan`, ipa: `ve-GAN-ski`},{pl: `bez`, sq: `pa`, ipa: `bez`},{pl: `z`, sq: `me`, ipa: `z`},{pl: `ostry`, sq: `pikant`, ipa: `OS-tri`},{pl: `słodki`, sq: `i ëmbël`, ipa: `SWOT-ki`}], phrases: [{pl: `Mam alergię na orzechy.`, sq: `Kam alergji nga arrat.`, ipa: `mam a-LER-gjen na o-ZHE-hi`},{pl: `Czy to zawiera gluten?`, sq: `A përmban kjo gluten?`, ipa: `çi to za-VJE-ra GLU-ten`},{pl: `Czy macie dania wegetariańskie?`, sq: `A keni pjata vegjetariane?`, ipa: `çi MA-çje DA-nja ve-ge-ta-RJAN-skje`},{pl: `Bez mleka, proszę.`, sq: `Pa qumësht, ju lutem.`, ipa: `bez MLE-ka, PRO-she`},{pl: `Nie jem mięsa.`, sq: `Nuk ha mish.`, ipa: `nje jem MJEN-sa`},{pl: `Czy to jest ostre?`, sq: `A është kjo pikante?`, ipa: `çi to jest OS-tre`}], grammar: `Mam alergię na... do të thotë “kam alergji ndaj...”. Për të thënë “nuk ha”, përdor Nie jem. Kjo është shumë praktike: Nie jem mięsa, Nie jem ryby. Për ushqime pa përbërës përdor bez: bez mleka, bez glutenu.`, practice: [`Thuaj se ke alergji nga arrat.`,`Pyet nëse ushqimi përmban gluten.`,`Thuaj se nuk ha mish.`,`Kërko diçka pa qumësht.`,`Shkruaj një dialog ku shpjegon një alergji në restorant.`]},{day: 16, title: `Blerjet bazë`, title_native: `Podstawowe zakupy`, focus: `Sot mëson të blesh produkte të vogla në dyqan, supermarket ose kioskë. Këto fraza janë të dobishme për ujë, ushqime të shpejta, karta SIM ose suvenire.`, vocab: [{pl: `sklep`, sq: `dyqan`, ipa: `sklep`},{pl: `supermarket`, sq: `supermarket`, ipa: `su-per-MAR-ket`},{pl: `kasa`, sq: `arkë`, ipa: `KA-sa`},{pl: `paragon`, sq: `kupon / faturë`, ipa: `pa-RA-gon`},{pl: `torba`, sq: `qese / çantë`, ipa: `TOR-ba`},{pl: `woda`, sq: `ujë`, ipa: `VO-da`},{pl: `chleb`, sq: `bukë`, ipa: `hlep`},{pl: `karta`, sq: `kartë`, ipa: `KAR-ta`},{pl: `gotówka`, sq: `para në dorë`, ipa: `go-TUF-ka`},{pl: `cena`, sq: `çmim`, ipa: `TSE-na`}], phrases: [{pl: `Ile to kosztuje?`, sq: `Sa kushton kjo?`, ipa: `I-le to kosh-TU-ye`},{pl: `Poproszę torbę.`, sq: `Dua një qese, ju lutem.`, ipa: `po-PRO-she TOR-ben`},{pl: `Czy mogę zapłacić kartą?`, sq: `A mund të paguaj me kartë?`, ipa: `çi MO-gen za-PWA-çiç KAR-ton`},{pl: `Nie potrzebuję paragonu.`, sq: `Nuk më duhet kuponi.`, ipa: `nje po-tshe-BU-ye pa-RA-go-nu`},{pl: `Szukam wody.`, sq: `Po kërkoj ujë.`, ipa: `SHU-kam VO-di`},{pl: `To wszystko.`, sq: `Kaq është gjithçka.`, ipa: `to FSHIS-tko`}], grammar: `Szukam do të thotë “po kërkoj”. Pas kësaj, emri shpesh merr formë tjetër, por si udhëtar mund ta përdorësh me fjalën kryesore dhe njerëzit do të kuptojnë. Czy mogę...? është një mënyrë e sjellshme për “A mundem...?”`, practice: [`Pyet sa kushton një produkt.`,`Kërko një qese.`,`Thuaj se dëshiron të paguash me kartë.`,`Thuaj: “Kaq është gjithçka.”`,`Krijo një dialog të shkurtër në supermarket.`]},{day: 17, title: `Rrobat dhe madhësitë`, title_native: `Ubrania i rozmiary`, focus: `Sot mëson të kërkosh rroba, ngjyra dhe madhësi në dyqan. Kjo është e dobishme në qendra tregtare në Varshavë, Kraków ose Wrocław.`, vocab: [{pl: `ubrania`, sq: `rroba`, ipa: `u-BRA-nja`},{pl: `koszula`, sq: `këmishë`, ipa: `ko-SHU-la`},{pl: `spodnie`, sq: `pantallona`, ipa: `SPOD-nje`},{pl: `buty`, sq: `këpucë`, ipa: `BU-ti`},{pl: `rozmiar`, sq: `madhësi`, ipa: `ROZ-mjar`},{pl: `mały`, sq: `i vogël`, ipa: `MA-wi`},{pl: `średni`, sq: `mesatar`, ipa: `SHRED-nji`},{pl: `duży`, sq: `i madh`, ipa: `DU-zhi`},{pl: `kolor`, sq: `ngjyrë`, ipa: `KO-lor`},{pl: `czarny`, sq: `i zi`, ipa: `ÇAR-ni`}], phrases: [{pl: `Szukam koszuli.`, sq: `Po kërkoj një këmishë.`, ipa: `SHU-kam ko-SHU-li`},{pl: `Czy macie większy rozmiar?`, sq: `A keni madhësi më të madhe?`, ipa: `çi MA-çje VJENK-shi ROZ-mjar`},{pl: `Czy mogę przymierzyć?`, sq: `A mund ta provoj?`, ipa: `çi MO-gen pshi-MJE-zhiç`},{pl: `To jest za małe.`, sq: `Kjo është shumë e vogël.`, ipa: `to jest za MA-we`},{pl: `To jest za duże.`, sq: `Kjo është shumë e madhe.`, ipa: `to jest za DU-zhe`},{pl: `Podoba mi się ten kolor.`, sq: `Më pëlqen kjo ngjyrë.`, ipa: `po-DO-ba mi shen ten KO-lor`}], grammar: `Za małe dhe za duże do të thonë “shumë e vogël” dhe “shumë e madhe”. Czy mogę przymierzyć? është frazë shumë e rëndësishme në dyqan rrobash. Në polonisht, ngjyrat ndryshojnë sipas gjinisë së emrit, por fillimisht mjafton të njohësh formën bazë.`, practice: [`Kërko një këmishë.`,`Pyet për madhësi më të madhe.`,`Thuaj se diçka është shumë e vogël.`,`Thuaj se të pëlqen ngjyra.`,`Bëj një dialog me një shitës rrobash.`]},{day: 18, title: `Tregu dhe ushqimet e freskëta`, title_native: `Targ i świeże produkty`, focus: `Sot mëson të blesh fruta, perime dhe produkte të freskëta në treg. Tregjet në Poloni janë vende të mira për të praktikuar gjuhën me fjali të shkurtra.`, vocab: [{pl: `targ`, sq: `treg`, ipa: `targ`},{pl: `jabłko`, sq: `mollë`, ipa: `YAB-wko`},{pl: `gruszka`, sq: `dardhë`, ipa: `GRUSH-ka`},{pl: `pomidor`, sq: `domate`, ipa: `po-MI-dor`},{pl: `ziemniaki`, sq: `patate`, ipa: `zhem-NJA-ki`},{pl: `ser`, sq: `djathë`, ipa: `ser`},{pl: `kiełbasa`, sq: `sallam polak`, ipa: `kjew-BA-sa`},{pl: `kilogram`, sq: `kilogram`, ipa: `ki-lo-GRAM`},{pl: `świeży`, sq: `i freskët`, ipa: `SHFJE-zhi`},{pl: `drogi`, sq: `i shtrenjtë`, ipa: `DRO-gi`}], phrases: [{pl: `Poproszę kilo jabłek.`, sq: `Dua një kilogram mollë, ju lutem.`, ipa: `po-PRO-she KI-lo YAB-wek`},{pl: `Czy to jest świeże?`, sq: `A është kjo e freskët?`, ipa: `çi to jest SHFJE-zhe`},{pl: `Ile kosztuje kilogram?`, sq: `Sa kushton kilogrami?`, ipa: `I-le kosh-TU-ye ki-lo-GRAM`},{pl: `Poproszę trochę sera.`, sq: `Dua pak djathë, ju lutem.`, ipa: `po-PRO-she TRO-hen SE-ra`},{pl: `To za dużo.`, sq: `Kjo është shumë.`, ipa: `to za DU-zho`},{pl: `Dziękuję, to wszystko.`, sq: `Faleminderit, kaq është gjithçka.`, ipa: `xhen-KU-ye, to FSHIS-tko`}], grammar: `Trochę do të thotë “pak” dhe përdoret shumë kur blen ushqim: trochę sera, trochę chleba. Kilo është formë e shkurtër për kilogram dhe kuptohet lehtë në treg. Për të mos blerë shumë, thuaj To za dużo.`, practice: [`Kërko një kilogram mollë.`,`Pyet sa kushton kilogrami.`,`Thuaj se dëshiron pak djathë.`,`Pyet nëse produkti është i freskët.`,`Krijo një dialog në treg në Gdańsk.`]},{day: 19, title: `Planifikimi i ditës`, title_native: `Planowanie dnia`, focus: `Sot mëson të flasësh për planet, oraret dhe aktivitetet turistike. Kjo të ndihmon kur organizon ditën në qytete si Kraków, Toruń ose Wrocław.`, vocab: [{pl: `dzisiaj`, sq: `sot`, ipa: `XHI-shaj`},{pl: `jutro`, sq: `nesër`, ipa: `YU-tro`},{pl: `rano`, sq: `herët`, ipa: `RA-no`},{pl: `wieczorem`, sq: `në mbrëmje`, ipa: `vje-ÇOR-em`},{pl: `plan`, sq: `plan`, ipa: `plan`},{pl: `spacer`, sq: `shëtitje`, ipa: `SPA-tser`},{pl: `muzeum`, sq: `muze`, ipa: `mu-ZE-um`},{pl: `zamek`, sq: `kështjellë`, ipa: `ZA-mek`},{pl: `park`, sq: `park`, ipa: `park`},{pl: `spotkanie`, sq: `takim`, ipa: `spot-KA-nje`}], phrases: [{pl: `Co robimy dzisiaj?`, sq: `Çfarë bëjmë sot?`, ipa: `tso ro-BI-mi XHI-shaj`},{pl: `Chcę iść do muzeum.`, sq: `Dua të shkoj në muze.`, ipa: `htse iç do mu-ZE-um`},{pl: `Jutro jedziemy do Krakowa.`, sq: `Nesër shkojmë në Kraków.`, ipa: `YU-tro je-DZE-mi do KRA-ko-va`},{pl: `Wieczorem idę na spacer.`, sq: `Në mbrëmje shkoj për shëtitje.`, ipa: `vje-ÇOR-em I-den na SPA-tser`},{pl: `O której zaczynamy?`, sq: `Në ç’orë fillojmë?`, ipa: `o KTU-rej za-çi-NA-mi`},{pl: `Mam wolny dzień.`, sq: `Kam ditë të lirë.`, ipa: `mam VOL-ni xhenj`}], grammar: `Idę përdoret kur shkon në këmbë ose në përgjithësi në një vend, ndërsa jadę përdoret kur shkon me transport. Chcę do të thotë “dua” dhe mund të ndiqet nga iść: Chcę iść do muzeum. Për plane, dzisiaj dhe jutro janë fjalë shumë të shpeshta.`, practice: [`Thuaj se sot do të shkosh në muze.`,`Pyet: “Çfarë bëjmë sot?”`,`Thuaj se nesër shkon në Kraków.`,`Krijo tre plane me dzisiaj, jutro dhe wieczorem.`,`Bëj dialog me një mik për planin e ditës.`]},{day: 20, title: `Muze, bileta dhe atraksione`, title_native: `Muzea, bilety i atrakcje`, focus: `Sot mëson të pyesësh për bileta, orare hapjeje dhe atraksione turistike. Kjo është e dobishme në muze historike, kështjella dhe ekspozita në Poloni.`, vocab: [{pl: `muzeum`, sq: `muze`, ipa: `mu-ZE-um`},{pl: `bilet`, sq: `biletë`, ipa: `BI-let`},{pl: `wystawa`, sq: `ekspozitë`, ipa: `vi-STA-va`},{pl: `zamek`, sq: `kështjellë`, ipa: `ZA-mek`},{pl: `przewodnik`, sq: `guidë`, ipa: `pshe-VOD-nik`},{pl: `godziny otwarcia`, sq: `orari i hapjes`, ipa: `go-DZHI-ni ot-FAR-ça`},{pl: `ulgowy`, sq: `me zbritje`, ipa: `ul-GO-vi`},{pl: `normalny`, sq: `normal`, ipa: `nor-MAL-ni`},{pl: `zamknięte`, sq: `mbyllur`, ipa: `zam-KNJE-te`},{pl: `otwarte`, sq: `hapur`, ipa: `ot-FAR-te`}], phrases: [{pl: `O której otwieracie?`, sq: `Në ç’orë hapeni?`, ipa: `o KTU-rej ot-fje-RA-çje`},{pl: `Do której jest otwarte?`, sq: `Deri në ç’orë është hapur?`, ipa: `do KTU-rej jest ot-FAR-te`},{pl: `Poproszę jeden bilet normalny.`, sq: `Dua një biletë normale, ju lutem.`, ipa: `po-PRO-she JE-den BI-let nor-MAL-ni`},{pl: `Czy jest przewodnik po angielsku?`, sq: `A ka guidë në anglisht?`, ipa: `çi jest pshe-VOD-nik po an-GJEL-sku`},{pl: `Czy można robić zdjęcia?`, sq: `A mund të bëhen foto?`, ipa: `çi MOZH-na RO-biç ZDJEN-ça`},{pl: `Muzeum jest zamknięte.`, sq: `Muzeu është i mbyllur.`, ipa: `mu-ZE-um jest zam-KNJE-te`}], grammar: `Można do të thotë “mundet” ose “lejohet” në mënyrë të përgjithshme. Czy można robić zdjęcia? është shumë praktike në muze. Otwarte dhe zamknięte përdoren për vende që janë hapur ose mbyllur.`, practice: [`Pyet në ç’orë hapet muzeu.`,`Kërko një biletë normale.`,`Pyet nëse lejohet të bësh foto.`,`Pyet nëse ka guidë në anglisht.`,`Krijo dialog në hyrje të një kështjelle.`]},{day: 21, title: `Moti dhe veshja`, title_native: `Pogoda i ubranie`, focus: `Sot mëson të flasësh për motin, shumë e rëndësishme sepse moti në Poloni mund të ndryshojë shpejt. Kjo të ndihmon të planifikosh shëtitje, muze ose transport.`, vocab: [{pl: `pogoda`, sq: `mot`, ipa: `po-GO-da`},{pl: `słońce`, sq: `diell`, ipa: `SWON-tse`},{pl: `deszcz`, sq: `shi`, ipa: `deshç`},{pl: `śnieg`, sq: `borë`, ipa: `shnjeɡ`},{pl: `wiatr`, sq: `erë`, ipa: `vjatr`},{pl: `zimno`, sq: `ftohtë`, ipa: `ZHIM-no`},{pl: `ciepło`, sq: `ngrohtë`, ipa: `ÇEP-wo`},{pl: `gorąco`, sq: `nxehtë`, ipa: `go-RON-tso`},{pl: `parasol`, sq: `çadër`, ipa: `pa-RA-sol`},{pl: `kurtka`, sq: `xhaketë`, ipa: `KURT-ka`}], phrases: [{pl: `Jaka jest pogoda?`, sq: `Si është moti?`, ipa: `JA-ka jest po-GO-da`},{pl: `Pada deszcz.`, sq: `Po bie shi.`, ipa: `PA-da deshç`},{pl: `Jest zimno.`, sq: `Është ftohtë.`, ipa: `jest ZHIM-no`},{pl: `Potrzebuję parasola.`, sq: `Kam nevojë për çadër.`, ipa: `po-tshe-BU-ye pa-RA-so-la`},{pl: `Dzisiaj jest ciepło.`, sq: `Sot është ngrohtë.`, ipa: `XHI-shaj jest ÇEP-wo`},{pl: `Czy jutro będzie śnieg?`, sq: `A do të ketë borë nesër?`, ipa: `çi YU-tro BEN-xhe shnjeɡ`}], grammar: `Në polonisht, për motin shpesh përdoret Jest...: Jest zimno, Jest ciepło, Jest gorąco. Për shi thuhet Pada deszcz, fjalë për fjalë “bie shi”. Będzie do të thotë “do të jetë” ose “do të ketë” për të ardhmen.`, practice: [`Pyet si është moti.`,`Thuaj se po bie shi.`,`Thuaj se ke nevojë për çadër.`,`Pyet nëse nesër do të ketë borë.`,`Krijo një dialog për motin para një shëtitjeje.`]},{day: 22, title: `Telefoni, interneti dhe karta SIM`, title_native: `Telefon, internet i karta SIM`, focus: `Sot mëson fraza për internetin, telefonin dhe blerjen e kartës SIM. Kjo është shumë e dobishme në aeroport, qendër tregtare ose dyqan telefoni.`, vocab: [{pl: `telefon`, sq: `telefon`, ipa: `te-LE-fon`},{pl: `internet`, sq: `internet`, ipa: `IN-ter-net`},{pl: `karta SIM`, sq: `kartë SIM`, ipa: `KAR-ta sim`},{pl: `hasło`, sq: `fjalëkalim`, ipa: `HAS-wo`},{pl: `Wi-Fi`, sq: `Wi-Fi`, ipa: `VAJ-faj`},{pl: `ładowarka`, sq: `karikues`, ipa: `wa-do-VAR-ka`},{pl: `bateria`, sq: `bateri`, ipa: `ba-TE-rja`},{pl: `numer`, sq: `numër`, ipa: `NU-mer`},{pl: `sklep telefoniczny`, sq: `dyqan telefoni`, ipa: `sklep te-le-fo-NIÇ-ni`},{pl: `działa`, sq: `punon`, ipa: `DZJA-wa`}], phrases: [{pl: `Czy macie kartę SIM?`, sq: `A keni kartë SIM?`, ipa: `çi MA-çje KAR-ten sim`},{pl: `Potrzebuję internetu.`, sq: `Kam nevojë për internet.`, ipa: `po-tshe-BU-ye IN-ter-ne-tu`},{pl: `Jakie jest hasło do Wi-Fi?`, sq: `Cili është fjalëkalimi i Wi-Fi?`, ipa: `JA-kje jest HAS-wo do VAJ-faj`},{pl: `Mój telefon nie działa.`, sq: `Telefoni im nuk punon.`, ipa: `muy te-LE-fon nje DZJA-wa`},{pl: `Potrzebuję ładowarki.`, sq: `Kam nevojë për karikues.`, ipa: `po-tshe-BU-ye wa-do-VAR-ki`},{pl: `Czy mogę tu naładować telefon?`, sq: `A mund ta karikoj telefonin këtu?`, ipa: `çi MO-gen tu na-wa-DO-vaç te-LE-fon`}], grammar: `Do në polonisht përdoret shpesh për “për” ose “i/e” në shprehje si hasło do Wi-Fi dhe ładowarka do telefonu. Potrzebuję do të thotë “kam nevojë për” dhe është shumë e dobishme për udhëtarët. Nie działa mbetet frazë kyçe për çdo problem teknik.`, practice: [`Pyet për fjalëkalimin e Wi-Fi.`,`Thuaj se ke nevojë për kartë SIM.`,`Thuaj se telefoni nuk punon.`,`Kërko një karikues.`,`Bëj dialog në një dyqan telefoni.`]},{day: 23, title: `Shëndeti dhe farmacia`, title_native: `Zdrowie i apteka`, focus: `Sot mëson fjalë për shëndetin, dhimbjen dhe farmacinë. Këto fraza janë të rëndësishme kur ke dhimbje koke, alergji ose nevojë për ilaçe gjatë udhëtimit.`, vocab: [{pl: `apteka`, sq: `farmaci`, ipa: `ap-TE-ka`},{pl: `lekarz`, sq: `mjek`, ipa: `LE-kazh`},{pl: `ból`, sq: `dhimbje`, ipa: `bul`},{pl: `głowa`, sq: `kokë`, ipa: `GWO-va`},{pl: `brzuch`, sq: `bark`, ipa: `bzhuh`},{pl: `gardło`, sq: `fyt`, ipa: `GAR-dwo`},{pl: `lek`, sq: `ilaç`, ipa: `lek`},{pl: `recepta`, sq: `recetë`, ipa: `re-TSEP-ta`},{pl: `gorączka`, sq: `temperaturë`, ipa: `go-RONÇ-ka`},{pl: `kaszel`, sq: `kollë`, ipa: `KA-shel`}], phrases: [{pl: `Gdzie jest apteka?`, sq: `Ku është farmacia?`, ipa: `gje jest ap-TE-ka`},{pl: `Boli mnie głowa.`, sq: `Më dhemb koka.`, ipa: `BO-li mnje GWO-va`},{pl: `Boli mnie brzuch.`, sq: `Më dhemb barku.`, ipa: `BO-li mnje bzhuh`},{pl: `Mam gorączkę.`, sq: `Kam temperaturë.`, ipa: `mam go-RONÇ-ken`},{pl: `Potrzebuję lekarza.`, sq: `Kam nevojë për mjek.`, ipa: `po-tshe-BU-ye LE-ka-zha`},{pl: `Czy potrzebuję recepty?`, sq: `A më duhet recetë?`, ipa: `çi po-tshe-BU-ye re-TSEP-ti`}], grammar: `Boli mnie... do të thotë “më dhemb...” dhe përdoret me pjesë të trupit: Boli mnie głowa, Boli mnie gardło. Mam përdoret për gjendje si Mam gorączkę ose Mam alergię. Në Poloni, disa ilaçe kërkojnë recepta, pra recetë mjekësore.`, practice: [`Pyet ku është farmacia.`,`Thuaj se të dhemb koka.`,`Thuaj se ke temperaturë.`,`Pyet nëse të duhet recetë.`,`Krijo dialog me farmacistin për dhimbje fyti.`]},{day: 24, title: `Emergjencat dhe siguria`, title_native: `Nagłe sytuacje i bezpieczeństwo`, focus: `Sot mëson fraza për situata urgjente dhe siguri personale. Qëllimi është të kërkosh ndihmë qartë në rast humbjeje, vjedhjeje ose problemi shëndetësor.`, vocab: [{pl: `pomocy`, sq: `ndihmë`, ipa: `PO-mo-tsi`},{pl: `policja`, sq: `polici`, ipa: `po-LI-tsja`},{pl: `szpital`, sq: `spital`, ipa: `SHPI-tal`},{pl: `ambulans`, sq: `ambulancë`, ipa: `am-BU-lans`},{pl: `zgubiłem`, sq: `humba`, ipa: `zgu-BI-wem`},{pl: `zgubiłam`, sq: `humba`, ipa: `zgu-BI-wam`},{pl: `portfel`, sq: `portofol`, ipa: `PORT-fel`},{pl: `telefon`, sq: `telefon`, ipa: `te-LE-fon`},{pl: `niebezpieczne`, sq: `e rrezikshme`, ipa: `nje-bez-PJEÇ-ne`},{pl: `adres`, sq: `adresë`, ipa: `A-dres`}], phrases: [{pl: `Pomocy!`, sq: `Ndihmë!`, ipa: `PO-mo-tsi`},{pl: `Proszę wezwać policję.`, sq: `Ju lutem thirrni policinë.`, ipa: `PRO-she VEZ-vaç po-LI-tsjen`},{pl: `Potrzebuję ambulansu.`, sq: `Kam nevojë për ambulancë.`, ipa: `po-tshe-BU-ye am-BU-lan-su`},{pl: `Zgubiłem portfel.`, sq: `Humba portofolin.`, ipa: `zgu-BI-wem PORT-fel`},{pl: `Zgubiłam telefon.`, sq: `Humba telefonin.`, ipa: `zgu-BI-wam te-LE-fon`},{pl: `To jest mój adres.`, sq: `Kjo është adresa ime.`, ipa: `to jest muy A-dres`}], grammar: `Në polonisht, folja mund të ndryshojë sipas gjinisë së folësit në të kaluarën. Një burrë thotë Zgubiłem, një grua thotë Zgubiłam. Për situata urgjente, frazat e shkurtra janë më të mira: Pomocy, Policja, Ambulans.`, practice: [`Thuaj me zë të lartë: Pomocy!`,`Thuaj se ke humbur portofolin.`,`Kërko ambulancë.`,`Kërko që dikush të thërrasë policinë.`,`Krijo dialog me një punonjës policie.`]},{day: 25, title: `Takime sociale dhe biseda të vogla`, title_native: `Spotkania i małe rozmowy`, focus: `Sot mëson të bësh biseda të lehta me vendas ose udhëtarë të tjerë. Kjo është e dobishme në bare, ture, hostele ose evente kulturore.`, vocab: [{pl: `miło`, sq: `kënaqësi`, ipa: `MI-wo`},{pl: `spotkanie`, sq: `takim`, ipa: `spot-KA-nje`},{pl: `przyjaciel`, sq: `mik`, ipa: `pshi-YA-çel`},{pl: `przyjaciółka`, sq: `mike`, ipa: `pshi-ya-ÇUL-ka`},{pl: `rozmowa`, sq: `bisedë`, ipa: `roz-MO-va`},{pl: `muzyka`, sq: `muzikë`, ipa: `mu-ZI-ka`},{pl: `film`, sq: `film`, ipa: `film`},{pl: `podróż`, sq: `udhëtim`, ipa: `PO-drush`},{pl: `ładny`, sq: `i bukur`, ipa: `WAD-ni`},{pl: `ciekawy`, sq: `interesant`, ipa: `çje-KA-vi`}], phrases: [{pl: `Miło cię poznać.`, sq: `Kënaqësi që të njoh.`, ipa: `MI-wo çen POZ-naç`},{pl: `Skąd jesteś?`, sq: `Nga je?`, ipa: `skond JES-tesh`},{pl: `Jak długo jesteś w Polsce?`, sq: `Sa kohë ke në Poloni?`, ipa: `jak DLU-go JES-tesh v POL-sçe`},{pl: `Lubię polską muzykę.`, sq: `Më pëlqen muzika polake.`, ipa: `LU-bjen POL-skon mu-ZI-ken`},{pl: `To bardzo ciekawe.`, sq: `Kjo është shumë interesante.`, ipa: `to BAR-dzo çje-KA-ve`},{pl: `Masz ochotę na kawę?`, sq: `Ke dëshirë për kafe?`, ipa: `mash o-HO-ten na KA-ven`}], grammar: `Lubię do të thotë “më pëlqen” ose “dua” në kuptimin e preferencës. Mund të thuash Lubię muzykę, Lubię kawę, Lubię Kraków. Masz ochotę na...? është mënyrë natyrale për të propozuar diçka: kafe, shëtitje ose darkë.`, practice: [`Pyet dikë nga është.`,`Thuaj se të pëlqen muzika polake.`,`Pyet sa kohë ka dikush në Poloni.`,`Propozo një kafe.`,`Krijo një dialog bisedë të vogël në hostel.`]},{day: 26, title: `Ftesa dhe plane me njerëz të tjerë`, title_native: `Zaproszenia i wspólne plany`, focus: `Sot mëson të pranosh, refuzosh dhe të propozosh plane në mënyrë të sjellshme. Kjo të ndihmon në situata sociale me vendas ose miq të rinj në udhëtim.`, vocab: [{pl: `zaproszenie`, sq: `ftesë`, ipa: `za-pro-SHE-nje`},{pl: `dzisiaj`, sq: `sot`, ipa: `XHI-shaj`},{pl: `jutro`, sq: `nesër`, ipa: `YU-tro`},{pl: `wieczór`, sq: `mbrëmje`, ipa: `VJE-çur`},{pl: `czas`, sq: `kohë`, ipa: `ças`},{pl: `chętnie`, sq: `me kënaqësi`, ipa: `HENJ-tne`},{pl: `niestety`, sq: `fatkeqësisht`, ipa: `nje-STE-ti`},{pl: `może`, sq: `ndoshta`, ipa: `MO-zhe`},{pl: `razem`, sq: `bashkë`, ipa: `RA-zem`},{pl: `później`, sq: `më vonë`, ipa: `PUZH-njej`}], phrases: [{pl: `Chętnie.`, sq: `Me kënaqësi.`, ipa: `HENJ-tne`},{pl: `Niestety, nie mogę.`, sq: `Fatkeqësisht, nuk mundem.`, ipa: `nje-STE-ti, nje MO-gen`},{pl: `Może jutro?`, sq: `Ndoshta nesër?`, ipa: `MO-zhe YU-tro`},{pl: `Masz czas dzisiaj?`, sq: `Ke kohë sot?`, ipa: `mash ças XHI-shaj`},{pl: `Chcesz iść razem?`, sq: `Do të shkosh bashkë?`, ipa: `hçesh iç RA-zem`},{pl: `Spotkajmy się później.`, sq: `Të takohemi më vonë.`, ipa: `spot-KAJ-mi shen PUZH-njej`}], grammar: `Chcesz do të thotë “a do?” ose “dëshiron?” në formë joformale. Me miq mund të thuash Chcesz iść razem? Për refuzim të sjellshëm, Niestety, nie mogę është frazë e thjeshtë dhe shumë e dobishme.`, practice: [`Prano një ftesë me Chętnie.`,`Refuzo me mirësjellje.`,`Propozo nesër.`,`Pyet dikë nëse ka kohë sot.`,`Bëj dialog për të planifikuar kafe në mbrëmje.`]},{day: 27, title: `Në bankë dhe këmbim valutor`, title_native: `Bank i kantor`, focus: `Sot mëson fraza për para, ATM, kartë dhe këmbim valutor. Kjo është e dobishme në zona turistike ku mund të duhet të përdorësh złoty.`, vocab: [{pl: `bank`, sq: `bankë`, ipa: `bank`},{pl: `kantor`, sq: `këmbimore`, ipa: `KAN-tor`},{pl: `bankomat`, sq: `bankomat`, ipa: `ban-KO-mat`},{pl: `pieniądze`, sq: `para`, ipa: `pje-NJON-dze`},{pl: `karta`, sq: `kartë`, ipa: `KAR-ta`},{pl: `gotówka`, sq: `para në dorë`, ipa: `go-TUF-ka`},{pl: `kurs`, sq: `kurs këmbimi`, ipa: `kurs`},{pl: `euro`, sq: `euro`, ipa: `EU-ro`},{pl: `złoty`, sq: `zloty`, ipa: `ZWO-ti`},{pl: `wypłata`, sq: `tërheqje parash`, ipa: `vi-PWA-ta`}], phrases: [{pl: `Gdzie jest bankomat?`, sq: `Ku është bankomati?`, ipa: `gje jest ban-KO-mat`},{pl: `Chcę wymienić euro.`, sq: `Dua të këmbej euro.`, ipa: `htse vi-MJE-niç EU-ro`},{pl: `Jaki jest kurs?`, sq: `Cili është kursi?`, ipa: `JA-ki jest kurs`},{pl: `Czy jest prowizja?`, sq: `A ka komision?`, ipa: `çi jest pro-VI-zja`},{pl: `Potrzebuję gotówki.`, sq: `Kam nevojë për para në dorë.`, ipa: `po-tshe-BU-ye go-TUF-ki`},{pl: `Karta nie działa.`, sq: `Karta nuk punon.`, ipa: `KAR-ta nje DZJA-wa`}], grammar: `Chcę do të thotë “dua” dhe është shumë i dobishëm me folje: Chcę wymienić, Chcę zapłacić, Chcę kupić. Kantor është fjala polake për këmbimore. Prowizja do të thotë komision, një fjalë e rëndësishme kur këmben para.`, practice: [`Pyet ku është bankomati.`,`Thuaj se dëshiron të këmbesh euro.`,`Pyet për kursin.`,`Pyet nëse ka komision.`,`Bëj dialog në një këmbimore.`]},{day: 28, title: `Posta dhe dërgesat`, title_native: `Poczta i wysyłka`, focus: `Sot mëson të dërgosh kartolina, pako ose letra nga Polonia. Kjo është e dobishme nëse do të dërgosh suvenire ose dokumente.`, vocab: [{pl: `poczta`, sq: `postë`, ipa: `POÇ-ta`},{pl: `list`, sq: `letër`, ipa: `list`},{pl: `kartka`, sq: `kartolinë`, ipa: `KART-ka`},{pl: `paczka`, sq: `pako`, ipa: `PAÇ-ka`},{pl: `znaczek`, sq: `pullë poste`, ipa: `ZNA-çek`},{pl: `adres`, sq: `adresë`, ipa: `A-dres`},{pl: `wysłać`, sq: `të dërgosh`, ipa: `VI-swaç`},{pl: `priorytet`, sq: `prioritet`, ipa: `prjo-RI-tet`},{pl: `ekonomiczny`, sq: `ekonomik`, ipa: `e-ko-no-MIÇ-ni`},{pl: `odbiór`, sq: `marrje`, ipa: `OD-bjur`}], phrases: [{pl: `Gdzie jest poczta?`, sq: `Ku është posta?`, ipa: `gje jest POÇ-ta`},{pl: `Chcę wysłać kartkę.`, sq: `Dua të dërgoj një kartolinë.`, ipa: `htse VI-swaç KART-ken`},{pl: `Poproszę znaczek do Albanii.`, sq: `Dua një pullë për Shqipëri, ju lutem.`, ipa: `po-PRO-she ZNA-çek do al-BA-nji`},{pl: `Ile kosztuje wysyłka?`, sq: `Sa kushton dërgesa?`, ipa: `I-le kosh-TU-ye vi-SIW-ka`},{pl: `Czy to jest priorytet?`, sq: `A është kjo prioritet?`, ipa: `çi to jest prjo-RI-tet`},{pl: `To jest adres.`, sq: `Kjo është adresa.`, ipa: `to jest A-dres`}], grammar: `Do Albanii do të thotë “për në Shqipëri” në kontekstin e dërgesës. Wysłać është infinitivi “të dërgosh”, dhe me Chcę formon Chcę wysłać. Në postë, mund të përdorësh fjalë të shkurtra si priorytet ose ekonomiczny për llojin e dërgesës.`, practice: [`Pyet ku është posta.`,`Kërko një pullë për Shqipëri.`,`Thuaj se do të dërgosh një kartolinë.`,`Pyet sa kushton dërgesa.`,`Krijo një dialog në postë.`]},{day: 29, title: `Pyetje të dobishme dhe zgjidhje problemesh`, title_native: `Przydatne pytania i rozwiązywanie problemów`, focus: `Sot bashkon shumë nga ato që ke mësuar dhe praktikon pyetje të dobishme për situata të paparashikuara. Kjo ditë të ndihmon të jesh më i pavarur në Poloni.`, vocab: [{pl: `dlaczego`, sq: `pse`, ipa: `dla-ÇE-go`},{pl: `kiedy`, sq: `kur`, ipa: `KJE-di`},{pl: `jak`, sq: `si`, ipa: `jak`},{pl: `ile`, sq: `sa`, ipa: `I-le`},{pl: `który`, sq: `cili`, ipa: `KTU-ri`},{pl: `problem`, sq: `problem`, ipa: `PRO-blem`},{pl: `zgoda`, sq: `dakord`, ipa: `ZGO-da`},{pl: `możliwe`, sq: `e mundur`, ipa: `mozh-LI-ve`},{pl: `niemożliwe`, sq: `e pamundur`, ipa: `nje-mozh-LI-ve`},{pl: `informacja`, sq: `informacion`, ipa: `in-for-MA-tsja`}], phrases: [{pl: `Mam pytanie.`, sq: `Kam një pyetje.`, ipa: `mam pi-TA-nje`},{pl: `Nie wiem.`, sq: `Nuk e di.`, ipa: `nje vjem`},{pl: `Czy to możliwe?`, sq: `A është e mundur?`, ipa: `çi to mozh-LI-ve`},{pl: `Jaki jest problem?`, sq: `Cili është problemi?`, ipa: `JA-ki jest PRO-blem`},{pl: `Gdzie mogę znaleźć informację?`, sq: `Ku mund të gjej informacion?`, ipa: `gje MO-gen ZNA-lezhç in-for-MA-tsjen`},{pl: `Czy może mi pan pomóc?`, sq: `A mund të më ndihmoni, zotëri?`, ipa: `çi MO-zhe mi pan PO-muts`}], grammar: `Fjalët pyetëse janë mjete të fuqishme: gdzie, kiedy, jak, ile, dlaczego. Mund t’i përdorësh edhe me fjali shumë të thjeshta. Czy może mi pan pomóc? është formale për një burrë, ndërsa Czy może mi pani pomóc? është formale për një grua.`, practice: [`Thuaj: “Kam një pyetje.”`,`Pyet ku mund të gjesh informacion.`,`Pyet nëse diçka është e mundur.`,`Kërko ndihmë nga një zonjë në formë formale.`,`Krijo një dialog ku zgjidh një problem me biletën.`]},{day: 30, title: `Rishikim i plotë për udhëtarin`, title_native: `Powtórka dla podróżnika`, focus: `Sot rishikon frazat më të rëndësishme për aeroport, hotel, ushqim, transport dhe emergjenca. Qëllimi është të ndihesh gati për një ditë të plotë në Poloni.`, vocab: [{pl: `podróż`, sq: `udhëtim`, ipa: `PO-drush`},{pl: `miasto`, sq: `qytet`, ipa: `MJAS-to`},{pl: `hotel`, sq: `hotel`, ipa: `HO-tel`},{pl: `bilet`, sq: `biletë`, ipa: `BI-let`},{pl: `jedzenie`, sq: `ushqim`, ipa: `je-DZE-nje`},{pl: `pomoc`, sq: `ndihmë`, ipa: `PO-mots`},{pl: `adres`, sq: `adresë`, ipa: `A-dres`},{pl: `czas`, sq: `kohë`, ipa: `ças`},{pl: `pieniądze`, sq: `para`, ipa: `pje-NJON-dze`},{pl: `dziękuję`, sq: `faleminderit`, ipa: `xhen-KU-ye`}], phrases: [{pl: `Dzień dobry, mam rezerwację.`, sq: `Mirëdita, kam rezervim.`, ipa: `xhen DO-bri, mam re-zer-VA-tsjen`},{pl: `Poproszę jeden bilet.`, sq: `Një biletë, ju lutem.`, ipa: `po-PRO-she JE-den BI-let`},{pl: `Gdzie jest najbliższa apteka?`, sq: `Ku është farmacia më e afërt?`, ipa: `gje jest naj-BLIZH-sha ap-TE-ka`},{pl: `Czy mogę zapłacić kartą?`, sq: `A mund të paguaj me kartë?`, ipa: `çi MO-gen za-PWA-çiç KAR-ton`},{pl: `Nie rozumiem, proszę powtórzyć.`, sq: `Nuk kuptoj, ju lutem përsëriteni.`, ipa: `nje ro-ZU-mjem, PRO-she pov-TU-zhiç`},{pl: `Dziękuję za pomoc.`, sq: `Faleminderit për ndihmën.`, ipa: `xhen-KU-ye za PO-mots`}], grammar: `Në udhëtim, nuk duhet të flasësh perfekt; duhet të jesh i qartë dhe i sjellshëm. Kombino frazat që di: Dzień dobry + Mam pytanie + Gdzie jest...? ose Przepraszam + Nie rozumiem + Jeszcze raz, proszę. Këto kombinime të japin kontroll në shumicën e situatave.`, practice: [`Krijo një dialog check-in në hotel me 6 rreshta.`,`Porosit ushqim dhe kërko llogarinë.`,`Pyet për drejtimin drejt një muzeu.`,`Raporto se telefoni nuk punon.`,`Shkruaj një skenë të shkurtër ku përdor 10 fraza të kursit.`]}];

var CONVERSATIONS_SQ_PL = [{id: 1, title: `Porosi në kafene`, scene: `Je në një kafene të vogël në qendër të Kraków pas një shëtitjeje në Rynek Główny. Do të porosisësh kafe dhe një ëmbëlsirë, por dëshiron të pyesësh edhe për qumësht dhe sheqer.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, sq: `Mirëdita, çfarë t’ju sjell?`},{who: `you`, pl: `Dzień dobry, poproszę kawę.`, sq: `Mirëdita, dua një kafe, ju lutem.`},{who: `them`, pl: `Z mlekiem czy bez mleka?`, sq: `Me qumësht apo pa qumësht?`},{who: `you`, pl: `Z mlekiem, ale bez cukru.`, sq: `Me qumësht, por pa sheqer.`},{who: `them`, pl: `Czy coś jeszcze?`, sq: `Dëshironi diçka tjetër?`},{who: `you`, pl: `Tak, poproszę sernik.`, sq: `Po, dua sernik, ju lutem.`},{who: `them`, pl: `Na miejscu czy na wynos?`, sq: `Për këtu apo me vete?`},{who: `you`, pl: `Na miejscu, proszę.`, sq: `Për këtu, ju lutem.`},{who: `them`, pl: `To będzie dwadzieścia złotych.`, sq: `Bëjnë njëzet zloty.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, sq: `A mund të paguaj me kartë?`},{who: `them`, pl: `Tak, oczywiście.`, sq: `Po, sigurisht.`},{who: `you`, pl: `Dziękuję bardzo.`, sq: `Faleminderit shumë.`}]},{id: 2, title: `Check-in në hotel`, scene: `Mbërrin në hotel në Gdańsk pas një udhëtimi me tren. Ke rezervim dhe dëshiron të dish nëse mëngjesi është i përfshirë.`, lines: [{who: `them`, pl: `Dobry wieczór, witamy w hotelu.`, sq: `Mirëmbrëma, mirë se vini në hotel.`},{who: `you`, pl: `Dobry wieczór, mam rezerwację.`, sq: `Mirëmbrëma, kam rezervim.`},{who: `them`, pl: `Na jakie nazwisko?`, sq: `Në cilin mbiemër?`},{who: `you`, pl: `Na nazwisko Cannon.`, sq: `Në mbiemrin Cannon.`},{who: `them`, pl: `Poproszę paszport.`, sq: `Pasaportën, ju lutem.`},{who: `you`, pl: `Proszę, to mój paszport.`, sq: `Urdhëroni, kjo është pasaporta ime.`},{who: `them`, pl: `Pokój numer trzydzieści dwa.`, sq: `Dhoma numër tridhjetë e dy.`},{who: `you`, pl: `Czy śniadanie jest w cenie?`, sq: `A është mëngjesi i përfshirë në çmim?`},{who: `them`, pl: `Tak, od siódmej do dziesiątej.`, sq: `Po, nga ora shtatë deri në dhjetë.`},{who: `you`, pl: `Gdzie jest winda?`, sq: `Ku është ashensori?`},{who: `them`, pl: `Po prawej stronie.`, sq: `Në anën e djathtë.`},{who: `you`, pl: `Dziękuję, do widzenia.`, sq: `Faleminderit, mirupafshim.`}]},{id: 3, title: `Kërkimi i drejtimit`, scene: `Je në Varshavë dhe kërkon rrugën për në Stare Miasto. Ndalesh për të pyetur një vendas në mënyrë të sjellshme.`, lines: [{who: `you`, pl: `Przepraszam, mam pytanie.`, sq: `Më falni, kam një pyetje.`},{who: `them`, pl: `Tak, proszę.`, sq: `Po, urdhëroni.`},{who: `you`, pl: `Gdzie jest Stare Miasto?`, sq: `Ku është Qyteti i Vjetër?`},{who: `them`, pl: `Proszę iść prosto.`, sq: `Ju lutem shkoni drejt.`},{who: `you`, pl: `Prosto?`, sq: `Drejt?`},{who: `them`, pl: `Tak, prosto, a potem w lewo.`, sq: `Po, drejt dhe pastaj majtas.`},{who: `you`, pl: `Czy to jest daleko?`, sq: `A është larg?`},{who: `them`, pl: `Nie, to jest blisko.`, sq: `Jo, është afër.`},{who: `you`, pl: `Ile minut pieszo?`, sq: `Sa minuta në këmbë?`},{who: `them`, pl: `Około dziesięciu minut.`, sq: `Rreth dhjetë minuta.`},{who: `you`, pl: `Dziękuję za pomoc.`, sq: `Faleminderit për ndihmën.`},{who: `them`, pl: `Nie ma za co.`, sq: `S’ka përse.`}]},{id: 4, title: `Darkë në restorant polak`, scene: `Je në një restorant tradicional në Kraków dhe dëshiron të provosh ushqim lokal. Pyet kamerierin për rekomandim dhe kontrollon nëse pjata ka mish.`, lines: [{who: `them`, pl: `Dobry wieczór, stolik dla jednej osoby?`, sq: `Mirëmbrëma, tavolinë për një person?`},{who: `you`, pl: `Tak, dla jednej osoby, proszę.`, sq: `Po, për një person, ju lutem.`},{who: `them`, pl: `Proszę, tutaj jest menu.`, sq: `Urdhëroni, këtu është menuja.`},{who: `you`, pl: `Co pani poleca?`, sq: `Çfarë rekomandoni, zonjë?`},{who: `them`, pl: `Polecam pierogi i barszcz.`, sq: `Rekomandoj pierogi dhe barszcz.`},{who: `you`, pl: `Czy pierogi są z mięsem?`, sq: `A janë pierogi me mish?`},{who: `them`, pl: `Mamy z mięsem i z serem.`, sq: `Kemi me mish dhe me djathë.`},{who: `you`, pl: `Poproszę pierogi z serem.`, sq: `Dua pierogi me djathë, ju lutem.`},{who: `them`, pl: `Coś do picia?`, sq: `Diçka për të pirë?`},{who: `you`, pl: `Wodę, proszę.`, sq: `Ujë, ju lutem.`},{who: `them`, pl: `Oczywiście.`, sq: `Sigurisht.`},{who: `you`, pl: `Dziękuję.`, sq: `Faleminderit.`}]},{id: 5, title: `Blerja e biletës së tramvajit`, scene: `Je në Wrocław dhe do të marrësh tramvajin për në qendër. Pyet për biletën dhe kontrollon nëse linja shkon në drejtimin e duhur.`, lines: [{who: `them`, pl: `Dzień dobry, słucham.`, sq: `Mirëdita, ju dëgjoj.`},{who: `you`, pl: `Dzień dobry, poproszę jeden bilet normalny.`, sq: `Mirëdita, dua një biletë normale.`},{who: `them`, pl: `Na ile minut?`, sq: `Për sa minuta?`},{who: `you`, pl: `Na dwadzieścia minut, proszę.`, sq: `Për njëzet minuta, ju lutem.`},{who: `them`, pl: `Proszę bardzo.`, sq: `Urdhëroni.`},{who: `you`, pl: `Czy ten bilet jest ważny w tramwaju?`, sq: `A është kjo biletë e vlefshme në tramvaj?`},{who: `them`, pl: `Tak, w tramwaju i autobusie.`, sq: `Po, në tramvaj dhe autobus.`},{who: `you`, pl: `Która linia jedzie do centrum?`, sq: `Cila linjë shkon në qendër?`},{who: `them`, pl: `Linia cztery jedzie do centrum.`, sq: `Linja katër shkon në qendër.`},{who: `you`, pl: `Gdzie jest przystanek?`, sq: `Ku është stacioni?`},{who: `them`, pl: `Tam, po lewej stronie.`, sq: `Atje, në anën e majtë.`},{who: `you`, pl: `Dziękuję bardzo.`, sq: `Faleminderit shumë.`}]},{id: 6, title: `Blerje në dyqan`, scene: `Je në një dyqan ushqimor në Poznań dhe dëshiron të blesh ujë, bukë dhe një qese. Përdor fraza të shkurtra dhe të sjellshme në arkë.`, lines: [{who: `them`, pl: `Dzień dobry.`, sq: `Mirëdita.`},{who: `you`, pl: `Dzień dobry.`, sq: `Mirëdita.`},{who: `them`, pl: `Czy to wszystko?`, sq: `A është kjo gjithçka?`},{who: `you`, pl: `Tak, to wszystko.`, sq: `Po, kaq është gjithçka.`},{who: `them`, pl: `Potrzebuje pan torby?`, sq: `A ju duhet qese, zotëri?`},{who: `you`, pl: `Tak, poproszę torbę.`, sq: `Po, dua një qese.`},{who: `them`, pl: `To będzie piętnaście złotych.`, sq: `Bëjnë pesëmbëdhjetë zloty.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, sq: `A mund të paguaj me kartë?`},{who: `them`, pl: `Tak, proszę.`, sq: `Po, urdhëroni.`},{who: `you`, pl: `Czy potrzebuję paragonu?`, sq: `A më duhet kuponi?`},{who: `them`, pl: `To zależy od pana.`, sq: `Varet nga ju.`},{who: `you`, pl: `Nie, dziękuję.`, sq: `Jo, faleminderit.`}]},{id: 7, title: `Në farmaci`, scene: `Je në një farmaci në Varshavë sepse të dhemb koka. Dëshiron të shpjegosh simptomën dhe të pyesësh nëse duhet recetë.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, sq: `Mirëdita, si mund të ndihmoj?`},{who: `you`, pl: `Dzień dobry, boli mnie głowa.`, sq: `Mirëdita, më dhemb koka.`},{who: `them`, pl: `Od kiedy?`, sq: `Që kur?`},{who: `you`, pl: `Od rana.`, sq: `Që në mëngjes.`},{who: `them`, pl: `Czy ma pan gorączkę?`, sq: `A keni temperaturë, zotëri?`},{who: `you`, pl: `Nie, nie mam gorączki.`, sq: `Jo, nuk kam temperaturë.`},{who: `them`, pl: `Mogę polecić ten lek.`, sq: `Mund t’ju rekomandoj këtë ilaç.`},{who: `you`, pl: `Czy potrzebuję recepty?`, sq: `A më duhet recetë?`},{who: `them`, pl: `Nie, bez recepty.`, sq: `Jo, pa recetë.`},{who: `you`, pl: `Ile to kosztuje?`, sq: `Sa kushton kjo?`},{who: `them`, pl: `Dwanaście złotych.`, sq: `Dymbëdhjetë zloty.`},{who: `you`, pl: `Poproszę.`, sq: `E marr, ju lutem.`}]},{id: 8, title: `Bisedë e vogël me një vendas`, scene: `Je në një tur në Toruń dhe fillon një bisedë të thjeshtë me një vendas. Flisni për origjinën, kohën në Poloni dhe planet për më vonë.`, lines: [{who: `you`, pl: `Cześć, jestem Arben.`, sq: `Ç’kemi, jam Arben.`},{who: `them`, pl: `Cześć, miło cię poznać.`, sq: `Ç’kemi, kënaqësi që të njoh.`},{who: `you`, pl: `Miło mi, skąd jesteś?`, sq: `Kënaqësi, nga je?`},{who: `them`, pl: `Jestem z Torunia, a ty?`, sq: `Jam nga Toruń, po ti?`},{who: `you`, pl: `Jestem z Albanii.`, sq: `Jam nga Shqipëria.`},{who: `them`, pl: `Jak długo jesteś w Polsce?`, sq: `Sa kohë ke në Poloni?`},{who: `you`, pl: `Jestem tutaj trzy dni.`, sq: `Kam tre ditë këtu.`},{who: `them`, pl: `Podoba ci się Polska?`, sq: `Të pëlqen Polonia?`},{who: `you`, pl: `Tak, bardzo podoba mi się Kraków i Toruń.`, sq: `Po, më pëlqejnë shumë Kraków dhe Toruń.`},{who: `them`, pl: `Masz plan na wieczór?`, sq: `Ke plan për mbrëmje?`},{who: `you`, pl: `Może pójdę na spacer.`, sq: `Ndoshta do të shkoj për shëtitje.`},{who: `them`, pl: `To dobry pomysł.`, sq: `Është ide e mirë.`}]}];